    Collections.sort(nodes, (a, b) -> {
        if (a[1] != b[1]) return a[1] - b[1]; // column
        if (a[0] != b[0]) return a[0] - b[0]; // row
        return a[2] - b[2]; // value
    });

    List> result = new ArrayList<>();
    int currentCol = nodes.get(0)[1];
    List currentList = new ArrayList<>();

