private void dfs(TreeNode node, int row, int col, List nodes) {
    if (node == null) return;

    nodes.add(new int[]{row, col, node.val});
    dfs(node.left, row + 1, col - 1, nodes);
    dfs(node.right, row + 1, col + 1, nodes);
}

public List<List<Integer>> verticalOrder(TreeNode root) {
    List<List<Integer>> result = new ArrayList<>();
    if (root == null) return result;
    TreeMap<Integer, List<Integer>> colMap = new TreeMap<>();
    Queue<int[]> queue = new LinkedList<>(); // [node_id, col]
    Map<Integer, TreeNode> idToNode = new HashMap<>();
    // Use a queue of Object arrays for (node, col)
    Queue<Object[]> bfsQueue = new LinkedList<>();
    bfsQueue.offer(new Object[]{root, 0});
    while (!bfsQueue.isEmpty()) {
        Object[] curr = bfsQueue.poll();
        TreeNode node = (TreeNode) curr[0];
        int col = (int) curr[1];
        colMap.computeIfAbsent(col, k -> new ArrayList<>()).add(node.val);
        if (node.left != null) bfsQueue.offer(new Object[]{node.left, col - 1});
        if (node.right != null) bfsQueue.offer(new Object[]{node.right, col + 1});
    }
    result.addAll(colMap.values());
    return result;
}

